import { useEffect, useState, useRef } from "react";

const LOGO_B64 = "";
const TOTAL_SECONDS = 10;

export default function SplashScreen({ onDone }) {
  const [progress, setProgress] = useState(0);
  const [secondsLeft, setSecondsLeft] = useState(TOTAL_SECONDS);
  const [done, setDone] = useState(false);
  const startRef = useRef(Date.now());

  useEffect(() => {
    const interval = setInterval(() => {
      const elapsed = (Date.now() - startRef.current) / 1000;
      const pct = Math.min(elapsed / TOTAL_SECONDS, 1);
      setProgress(pct);
      setSecondsLeft(Math.max(0, Math.ceil(TOTAL_SECONDS - elapsed)));
      if (pct >= 1) {
        clearInterval(interval);
        setDone(true);
        setTimeout(() => onDone(), 700);
      }
    }, 50);
    return () => clearInterval(interval);
  }, [onDone]);

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 9999,
      background: "radial-gradient(ellipse at center, #0d1b3e 0%, #050d1f 100%)",
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      opacity: done ? 0 : 1,
      transition: "opacity 0.7s ease",
      overflow: "hidden",
    }}>

      {/* Hexagon SVG pattern overlay */}
      <svg style={{ position:"absolute", inset:0, width:"100%", height:"100%", opacity:0.08 }} xmlns="http://www.w3.org/2000/svg">
        <defs>
          <pattern id="hex" x="0" y="0" width="56" height="48" patternUnits="userSpaceOnUse">
            <polygon points="28,2 54,14 54,34 28,46 2,34 2,14"
              fill="none" stroke="#4a7fd4" strokeWidth="1"/>
          </pattern>
        </defs>
        <rect width="100%" height="100%" fill="url(#hex)"/>
      </svg>

      {/* Blue diagonal glow wings */}
      <div style={{ position:"absolute", left:0, top:0, width:"28%", height:"100%",
        background:"linear-gradient(135deg, #1a3aaa44 0%, transparent 60%)",
        clipPath:"polygon(0 0, 100% 20%, 70% 80%, 0 100%)" }}/>
      <div style={{ position:"absolute", right:0, top:0, width:"28%", height:"100%",
        background:"linear-gradient(225deg, #1a3aaa44 0%, transparent 60%)",
        clipPath:"polygon(100% 0, 0 20%, 30% 80%, 100% 100%)" }}/>

      {/* Gold radial glow behind logo */}
      <div style={{
        position:"absolute",
        width:320, height:320,
        borderRadius:"50%",
        background:"radial-gradient(circle, #c8a84033 0%, transparent 70%)",
        animation:"pulse 3s ease-in-out infinite",
      }}/>

      {/* Logo */}
      <img
        src={`data:image/png;base64,${LOGO_B64}`}
        alt="EDUTEC Logo"
        style={{
          width: 280, height: "auto",
          borderRadius: 16,
          animation: "logoIn 0.8s cubic-bezier(0.34,1.56,0.64,1) both",
          filter: "drop-shadow(0 0 32px #c8a84066)",
          position: "relative", zIndex: 1,
        }}
      />

      {/* Progress bar */}
      <div style={{
        marginTop: 40, width: 280, height: 5,
        background: "#ffffff18", borderRadius: 999,
        overflow: "hidden", position: "relative", zIndex: 1,
      }}>
        <div style={{
          height: "100%",
          width: `${progress * 100}%`,
          background: "linear-gradient(90deg, #2b4ec0, #c8a840)",
          borderRadius: 999,
          transition: "width 0.1s linear",
        }}/>
      </div>

      {/* Status text */}
      <div style={{
        marginTop: 16, color: "#c8a840",
        fontFamily: "system-ui, sans-serif",
        fontSize: 14, letterSpacing: "0.1em",
        opacity: 0.9, zIndex: 1,
      }}>
        {done ? "¡Listo!" : `Cargando... ${secondsLeft}s`}
      </div>

      {/* Bouncing dots */}
<div style={{ display:"flex", gap:8, marginTop:12, zIndex:1 }}>
  {[0,1,2].map(i => (
    <div key={i} style={{
      width:8, height:8, borderRadius:"50%",
      background:"#4a7fd4",
      animation:`bounce 1.2s ease-in-out ${i*0.2}s infinite`,
    }}/>
  ))}
</div>

{/* Skip button */}
<button
  onClick={() => { setDone(true); setTimeout(() => onDone(), 700); }}
  style={{
    marginTop: 24, zIndex: 1,
    background: "transparent",
    border: "1px solid #c8a84066",
    color: "#c8a840",
    padding: "8px 28px",
    borderRadius: 999,
    fontSize: 13,
    letterSpacing: "0.08em",
    cursor: "pointer",
    fontFamily: "system-ui, sans-serif",
    transition: "all 0.2s",
  }}
  onMouseEnter={e => {
    e.currentTarget.style.background = "#c8a84022";
    e.currentTarget.style.borderColor = "#c8a840";
  }}
  onMouseLeave={e => {
    e.currentTarget.style.background = "transparent";
    e.currentTarget.style.borderColor = "#c8a84066";
  }}
>
  Saltar →
</button>
    </div>
  );
}
